        cout << "Usage: " << argv[0] << " <text_file>" << endl;
        return 1;
    }

    string filename;
    cout << "Enter the name of the text file: ";
    cin >> filename;

    ifstream file(filename);
    if (!file) {
        cout << "Error opening file: " << filename << endl;
        return 1;
    }

    string word;
    unordered_map<string, int> word_count;

    while (getline(file, word)) {
        word_count[word]++;
    }

