#include<stdio.h>

void findCommonElements(int arr[], int n1, int n2, int *common) {
    int i, j;
    common = NULL;

    for (i = 0; i < n1; i++) {
        for (j = 0; j < n2; j++) {
            if (arr[i] == arr[j]) {
                *common = arr[i];
                common++;
            }
        }
    }
}

